#!/usr/bin/env node
// Add one or more words to Blossom's word bank and rebuild the served word list.
// The counterpart to blossom-remove-word.js — use it whenever a real word the
// game rejects should start counting (slang like "yeet", a valid word SCOWL-60
// just doesn't carry, etc.):
//
//   node scripts/blossom-add-word.js <word> [word2 ...]
//   make blossom-add-word word="yeet zonk"
//
// Each word is added to:
//   • assets/blossom/word_bank.txt  — the generation pool (tracked in git)
// then assets/blossom/words.js is regenerated by invoking the build script.
//
// We add to word_bank.txt rather than scowl-60.txt because the bank is the
// committed, durable source — scowl-60.txt is gitignored and re-fetched on
// demand, so edits there wouldn't survive. The build merges the generation pool
// into the validation set, so a bank word becomes BOTH a valid play AND a
// possible daily target. That's usually what we want; if a word should validate
// but never be a target, the bank isn't the right home for it.
//
// Words are normalized to lowercase and must be 3-8 letters (a-z only): the
// build only pulls 3-8 letter entries out of the bank (longer words generate
// nothing and never reach validation from here), so anything outside that range
// is rejected rather than silently dropped at build time.

const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

const ROOT = path.join(__dirname, '..');
const WORD_BANK_PATH = path.join(ROOT, 'assets/blossom/word_bank.txt');
const BUILD_SCRIPT = path.join(__dirname, 'blossom-build-words.js');

const MIN_LEN = 3;
const MAX_LEN = 8; // GEN_MAX_LEN in blossom-build-words.js

const input = process.argv.slice(2).map(w => w.trim().toLowerCase()).filter(Boolean);
if (!input.length) {
  console.error('Usage: node scripts/blossom-add-word.js <word> [word2 ...]');
  process.exit(1);
}

const onlyLowerLetters = /^[a-z]+$/;
const targets = [];
for (const w of new Set(input)) {
  if (!onlyLowerLetters.test(w)) {
    console.warn(`  "${w}": skipped — letters a-z only`);
    continue;
  }
  if (w.length < MIN_LEN || w.length > MAX_LEN) {
    console.warn(`  "${w}": skipped — must be ${MIN_LEN}-${MAX_LEN} letters`);
    continue;
  }
  targets.push(w);
}
if (!targets.length) {
  console.log('Nothing valid to add — word list unchanged, skipping rebuild.');
  process.exit(0);
}

const existing = new Set(
  fs.readFileSync(WORD_BANK_PATH, 'utf8').split('\n').map(l => l.trim()).filter(Boolean)
);

const added = [];
for (const w of targets) {
  if (existing.has(w)) {
    console.log(`  "${w}": already in the bank`);
    continue;
  }
  existing.add(w);
  added.push(w);
}

if (!added.length) {
  console.log('Nothing new to add — word list unchanged, skipping rebuild.');
  process.exit(0);
}

// Keep the bank C-sorted (byte order) to match how it ships and to keep diffs
// minimal. localeCompare would interleave casing differently; everything here is
// already lowercase a-z, so plain comparison matches the existing `sort -c`.
const sorted = [...existing].sort();
fs.writeFileSync(WORD_BANK_PATH, sorted.join('\n') + '\n');
console.log(`Added to word_bank.txt: ${added.join(', ')}`);

console.log('Rebuilding assets/blossom/words.js …');
execFileSync('node', [BUILD_SCRIPT], { stdio: 'inherit' });
